  ]);
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

5. **Add a .gitignore** file:
```
node_modules/
.env
.env.local
*.log
```

